mapper.select:
SELECT sh.user_id AS userId, u.username AS username, u.real_name AS realName, COALESCE(sh.employee_type, u.employee_type) AS employeeType, sh.report_ym AS reportYm, sh.status AS status, COALESCE(it.cnt, 0) AS projectCount FROM dept_daily_user_month_report_sheet sh LEFT JOIN sys_user u ON u.tenant_id = sh.tenant_id AND u.id = sh.user_id LEFT JOIN ( SELECT tenant_id, report_ym, user_id, COUNT(DISTINCT project_id) AS cnt FROM dept_daily_user_month_report_item GROUP BY tenant_id, report_ym, user_id ) it ON it.tenant_id = sh.tenant_id AND it.report_ym = sh.report_ym AND it.user_id = sh.user_id WHERE sh.tenant_id = #{tenantId} AND sh.report_ym = #{reportYm}
AND sh.dept_id = #{deptId}
AND sh.office_id = #{officeId}
AND sh.employee_type = #{employeeType}
AND sh.status = #{status}
AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY sh.status ASC, u.real_name ASC, u.username ASC, sh.user_id ASC
